const productImage = document.querySelector('img[alt*="wernies"]');
if (productImage) {
    productImage.alt;
} else {
    // Look for any text with product information
    const productInfo = document.querySelector('[data-item-info]');
    if (productInfo) {
        JSON.parse(productInfo.getAttribute('data-item-info')).title;
    } else {
        "Product title not found on this page";
    }
}

